class MKAverage {
public:
    MKAverage(int m, int k) : m(m), k(k) {}

    void addElement(int num) {
        stream.push_back(num);
        if (stream.size() > m) {
            dq.push_front(stream.back());
            stream.pop_back();
        }
    }

    int calculateMKAverage() {
        if (stream.size() < m) return -1;
        while (dq.size() < m) {
            dq.push_back(stream.front());
            stream.pop_front();
        }
        sort(dq.begin() + k, dq.end() - k);
        int sum = 0;
        for (int i = k; i < m - k; ++i) {
            sum += dq[i];
        }
        return sum / (m - 2 * k);
    }

private:
    int m, k;
    deque<int> dq;
    list<int> stream;
};
